	SELECT SEQ_PLG_PB.NEXTVAL FROM DUAL

INSERT 
  INTO
		PROOF_BOARD 
	   ( 
		PROOF_NO
	   , USER_ID
	   , JOIN_NO
	   , TITLE
	   , CATEGORY
	   , QUANTITY
	   , CONTENT
	   , CREATE_DATE
	   , DELETED
	   , UPDATED 
	   ) 
VALUES 
	   ( 
		  #{proofNo}
	    , #{userId}
	    , #{joinNo}
	    , #{title}
	    , #{category}
	    , #{quantity}
	    , #{content}
	    , SYSDATE
	    , 'N'
	    , 'N' 
	    )

mapper.select:
SELECT P.PROOF_NO , P.USER_ID , P.JOIN_NO , P.TITLE , P.CATEGORY , P.QUANTITY , P.CONTENT , P.CREATE_DATE , UF.FILE_PATH || UF.CHANGE_NAME AS USER_PROFILE , PF.FILE_PATH || PF.CHANGE_NAME AS BOARD_PROFILE FROM PROOF_BOARD P LEFT JOIN USER_FILE UF ON UF.USER_ID = P.USER_ID LEFT JOIN PROOF_FILE PF ON PF.FILE_NO = ( SELECT MAX(FILE_NO) FROM PROOF_FILE WHERE PROOF_NO = P.PROOF_NO AND FILE_LEVEL = 1 AND DELETED = 'N' ) WHERE P.DELETED = 'N'
AND P.CATEGORY = #{category}
ORDER BY P.PROOF_NO DESC OFFSET #{pi.offset} ROWS FETCH NEXT #{pi.boardLimit} ROWS ONLY

mapper.update:
UPDATE PROOF_BOARD
SET DELETED = 'Y'
WHERE USER_ID = #{userId}
AND PROOF_NO = #{proofNo}

UPDATE 
		PROOF_BOARD
   SET
 		TITLE = #{title}

 	  , CATEGORY = #{category}
 	  , QUANTITY = #{quantity}
 	  , CONTENT = #{content}
 	  , UPDATED = 'Y'
  WHERE
		PROOF_NO = #{proofNo}
	AND
		USER_ID = #{userId}
